CREATE TABLE IF NOT EXISTS accounting_posts (
    id UUID NOT NULL DEFAULT gen_random_uuid(),
    company_id UUID NOT NULL,
    branch_id UUID,
    source_type posting_source_type NOT NULL,
    source_id UUID NOT NULL,
    source_reference TEXT,
