    max_retries INTEGER NOT NULL DEFAULT 3,
    next_retry_at TIMESTAMPTZ,
    error_code TEXT,
    error_message TEXT,
    reverses_post_id UUID,
    reversed_by_post_id UUID,
    posted_by UUID,
    notes TEXT,
